17: package org.apache.camel.component.direct;
18: 
19: import org.apache.camel.Category;
20: import org.apache.camel.Consumer;
21: import org.apache.camel.Processor;
22: import org.apache.camel.Producer;
23: import org.apache.camel.spi.Metadata;
24: import org.apache.camel.spi.UriEndpoint;
25: import org.apache.camel.spi.UriParam;
26: import org.apache.camel.spi.UriPath;
27: import org.apache.camel.support.DefaultEndpoint;
28: import org.apache.camel.util.StringHelper;
29: 
30: /**
31:  * Call another endpoint from the same Camel Context synchronously.
32:  *
33:  * This endpoint can be used to connect existing routes in the same CamelContext.
34:  */
35: @UriEndpoint(firstVersion = "1.0.0", scheme = "direct", title = "Direct", syntax = "direct:name",
36:              remote = false, category = { Category.CORE, Category.MESSAGING })
37: public class DirectEndpoint extends DefaultEndpoint {
38: 
39:     private final DirectComponent component;
40:     private final String key;
41: 
42:     @UriPath(description = "Name of direct endpoint")
43:     @Metadata(required = true)
44:     private String name;
45:     @UriParam(label = "advanced")
46:     private boolean synchronous;
47: 
48:     @UriParam(label = "producer", defaultValue = "true")
49:     private boolean block = true;
50:     @UriParam(label = "producer", defaultValue = "30000")
51:     private long timeout = 30000L;
52:     @UriParam(label = "producer", defaultValue = "true")
53:     private boolean failIfNoConsumers = true;
54: 
55:     public DirectEndpoint(String uri, DirectComponent component) {
56:         super(uri, component);
57:         this.component = component;
58: 
59:         this.key = StringHelper.before(uri, "?", uri);
60:     }
61: 
62:     @Override
63:     public boolean isRemote() {
64:         return false;
65:     }
66: 
67:     @Override
68:     public Producer createProducer() throws Exception {
69:         return new DirectProducer(this, key);
70:     }
71: 
72:     @Override
73:     public Consumer createConsumer(Processor processor) throws Exception {
74:         Consumer answer = new DirectConsumer(this, processor, key);
75:         configureConsumer(answer);
76:         return answer;
77:     }
78: 
79:     @Deprecated
80:     public DirectConsumer getConsumer() throws InterruptedException {
81:         return component.getConsumer(key, block, timeout);
82:     }
83: 
84:     public boolean isSynchronous() {
85:         return synchronous;
86:     }
87: 
88:     /**
89:      * Whether synchronous processing is forced.
90:      *
91:      * If enabled, then the producer thread will be forced to wait until the message has been completed before the same
92:      * thread will continue processing.
93:      *
94:      * If disabled, the default, then the producer thread may be freed and can do other work while the message is
95:      * continued processed by other threads (reactive).
96:      */
97:     public void setSynchronous(boolean synchronous) {
98:         this.synchronous = synchronous;
99:     }
100: 
101:     public boolean isBlock() {
102:         return block;
103:     }
104: 
105:     /**
106:      * If sending a message to a direct endpoint which has no active consumer, then we can tell the producer to block
107:      * and wait for the consumer to become active.
108:      */
109:     public void setBlock(boolean block) {
110:         this.block = block;
111:     }
112: 
113:     public long getTimeout() {
114:         return timeout;
115:     }
116: 
117:     /**
118:      * The timeout value to use if block is enabled.
119:      */
120:     public void setTimeout(long timeout) {
121:         this.timeout = timeout;
122:     }
123: 
124:     public boolean isFailIfNoConsumers() {
125:         return failIfNoConsumers;
126:     }
127: 
128:     /**
129:      * Whether the producer should fail by throwing an exception, when sending to a DIRECT endpoint with no active
130:      * consumers.
131:      */
132:     public void setFailIfNoConsumers(boolean failIfNoConsumers) {
133:         this.failIfNoConsumers = failIfNoConsumers;
134:     }
135: 
136: }
