17: package org.apache.camel.component.direct;
18: 
19: import org.apache.camel.AsyncCallback;
20: import org.apache.camel.Exchange;
21: import org.apache.camel.ExchangePropertyKey;
22: import org.apache.camel.support.DefaultAsyncProducer;
23: import org.slf4j.Logger;
24: import org.slf4j.LoggerFactory;
25: 
26: /**
27:  * The direct producer.
28:  */
29: public class DirectProducer extends DefaultAsyncProducer {
30: 
31:     private static final Logger LOG = LoggerFactory.getLogger(DirectProducer.class);
32: 
33:     private volatile DirectConsumer consumer;
34:     private int stateCounter;
35: 
36:     private final DirectEndpoint endpoint;
37:     private final DirectComponent component;
38:     private final String key;
39:     private final boolean block;
40:     private final long timeout;
41: 
42:     public DirectProducer(DirectEndpoint endpoint, String key) {
43:         super(endpoint);
44:         this.endpoint = endpoint;
45:         this.component = (DirectComponent) endpoint.getComponent();
46:         this.key = key;
47:         this.block = endpoint.isBlock();
48:         this.timeout = endpoint.getTimeout();
49:     }
50: 
51:     @Override
52:     public void process(Exchange exchange) throws Exception {
53:         if (consumer == null || stateCounter != component.getStateCounter()) {
54:             stateCounter = component.getStateCounter();
55:             consumer = component.getConsumer(key, block, timeout);
56:         }
57:         if (consumer == null) {
58:             if (endpoint.isFailIfNoConsumers()) {
59:                 throw new DirectConsumerNotAvailableException("No consumers available on endpoint: " + endpoint, exchange);
60:             } else {
61:                 LOG.debug("message ignored, no consumers available on endpoint: {}", endpoint);
62:             }
63:         } else {
64:             consumer.getProcessor().process(exchange);
65:         }
66:     }
67: 
68:     @Override
69:     public boolean process(Exchange exchange, AsyncCallback callback) {
70:         try {
71:             // we may be forced synchronous
72:             if (endpoint.isSynchronous()) {
73:                 process(exchange);
74:                 callback.done(true);
75:                 return true;
76:             }
77:             if (consumer == null || stateCounter != component.getStateCounter()) {
78:                 stateCounter = component.getStateCounter();
79:                 consumer = component.getConsumer(key, block, timeout);
80:             }
81:             if (consumer == null) {
82:                 if (endpoint.isFailIfNoConsumers()) {
83:                     exchange.setException(new DirectConsumerNotAvailableException(
84:                             "No consumers available on endpoint: " + endpoint, exchange));
85:                 } else {
86:                     LOG.debug("message ignored, no consumers available on endpoint: {}", endpoint);
87:                 }
88:                 callback.done(true);
89:                 return true;
90:             } else {
91:                 // the consumer may be forced synchronous
92:                 if (consumer.getEndpoint().isSynchronous()) {
93:                     consumer.getProcessor().process(exchange);
94:                     callback.done(true);
95:                     return true;
96:                 } else {
97:                     //Ensure we can close the CLIENT Scope created by this DirectProducer
98:                     //in the same thread
99:                     if (exchange.getProperty(ExchangePropertyKey.OTEL_ACTIVE_SPAN) != null) {
100:                         exchange.setProperty(ExchangePropertyKey.OTEL_CLOSE_CLIENT_SCOPE, Boolean.TRUE);
101:                     }
102:                     return consumer.getAsyncProcessor().process(exchange, callback);
103:                 }
104:             }
105:         } catch (InterruptedException e) {
106:             LOG.info("Interrupted while processing the exchange");
107:             Thread.currentThread().interrupt();
108:             exchange.setException(e);
109:             callback.done(true);
110:             return true;
111:         } catch (Exception e) {
112:             exchange.setException(e);
113:             callback.done(true);
114:             return true;
115:         }
116:     }
117: 
118: }
