25: /**
26:  * The direct consumer.
27:  */
28: public class DirectConsumer extends DefaultConsumer implements ShutdownAware, Suspendable {
29: 
30:     private final DirectComponent component;
31:     private final String key;
32: 
33:     public DirectConsumer(DirectEndpoint endpoint, Processor processor, String key) {
34:         super(endpoint, processor);
35:         this.component = (DirectComponent) endpoint.getComponent();
36:         this.key = key;
37:     }
38: 
39:     @Override
40:     public DirectEndpoint getEndpoint() {
41:         return (DirectEndpoint) super.getEndpoint();
42:     }
43: 
44:     @Override
45:     protected void doStart() throws Exception {
46:         super.doStart();
47:         component.addConsumer(key, this);
48:     }
49: 
50:     @Override
51:     protected void doStop() throws Exception {
52:         component.removeConsumer(key, this);
53:         super.doStop();
54:     }
55: 
56:     @Override
57:     protected void doSuspend() throws Exception {
58:         component.removeConsumer(key, this);
59:     }
60: 
61:     @Override
62:     protected void doResume() throws Exception {
63:         // resume by using the start logic
64:         component.addConsumer(key, this);
65:     }
66: 
67:     @Override
68:     public boolean deferShutdown(ShutdownRunningTask shutdownRunningTask) {
69:         // deny stopping on shutdown as we want direct consumers to run in case some other queues
70:         // depend on this consumer to run, so it can complete its exchanges
71:         return true;
72:     }
73: 
74:     @Override
75:     public int getPendingExchangesSize() {
76:         // return 0 as we do not have an internal memory queue with a variable size
77:         // of inflight messages.
78:         return 0;
79:     }
80: 
81:     @Override
82:     public void prepareShutdown(boolean suspendOnly, boolean forced) {
83:         // noop
84:     }
85: }
